61	struct GameState {
62	    std::array<std::array<int, GRID_SIZE>, GRID_SIZE> board; 
63	    std::vector<Candy> candies_list; 
64	    int turn_num_1_indexed; 
65	
66	    GameState() : turn_num_1_indexed(0) {
67	        for (int i = 0; i < GRID_SIZE; ++i) {
68	            board[i].fill(0); 
69	        }
70	        candies_list.reserve(NUM_TURNS);
71	    }
72	
73	    GameState(const GameState& other) = default; 
74	    GameState& operator=(const GameState& other) = default;
75	    GameState(GameState&& other) noexcept = default;
76	    GameState& operator=(GameState&& other) noexcept = default;
