83	    std::pair<int, int> find_pth_empty_cell(int p_1_indexed) const {
84	        int count = 0;
85	        for (int r_idx = 0; r_idx < GRID_SIZE; ++r_idx) {
86	            for (int c_idx = 0; c_idx < GRID_SIZE; ++c_idx) {
87	                if (board[r_idx][c_idx] == 0) { 
88	                    count++;
89	                    if (count == p_1_indexed) {
90	                        return {r_idx, c_idx};
91	                    }
92	                }
93	            }
94	        }
95	        return {-1, -1}; 
96	    }
97	    
98	    int count_empty_cells() const {
99	        return GRID_SIZE * GRID_SIZE - static_cast<int>(candies_list.size());
100	    }
