170	    long long calculate_sum_sq_comp_size() const {
171	        long long total_sq_sum = 0;
172	        std::array<std::array<bool, GRID_SIZE>, GRID_SIZE> visited;
173	        for (int i = 0; i < GRID_SIZE; ++i) visited[i].fill(false);
174	
175	        std::array<std::pair<int, int>, GRID_SIZE * GRID_SIZE> q_arr; 
176	
177	        for (int r_start = 0; r_start < GRID_SIZE; ++r_start) {
178	            for (int c_start = 0; c_start < GRID_SIZE; ++c_start) {
179	                if (board[r_start][c_start] != 0 && !visited[r_start][c_start]) {
180	                    int current_flavor = board[r_start][c_start];
181	                    long long current_comp_size = 0;
182	                    
183	                    q_arr[0] = {r_start, c_start};
184	                    visited[r_start][c_start] = true;
185	                    int head = 0; 
186	                    int tail = 1; 
187	                    
188	                    while(head < tail){
189	                        current_comp_size++; 
190	                        const std::pair<int,int>& curr_cell = q_arr[head];
191	                        const int curr_r = curr_cell.first;
192	                        const int curr_c = curr_cell.second;
193	                        head++; 
194	
195	                        for (int i = 0; i < NUM_DIRECTIONS; ++i) {
196	                            int nr = curr_r + DR[i];
197	                            int nc = curr_c + DC[i];
198	                            if (nr >= 0 && nr < GRID_SIZE && nc >= 0 && nc < GRID_SIZE &&
199	                                !visited[nr][nc] && board[nr][nc] == current_flavor) {
200	                                visited[nr][nc] = true;
201	                                q_arr[tail++] = {nr, nc}; 
202	                            }
203	                        }
204	                    }
205	                    total_sq_sum += current_comp_size * current_comp_size;
206	                }
207	            }
208	        }
209	        return total_sq_sum;
210	    }
211	    
212	    double calculate_distance_penalty_CoM() const {
213	        if (candies_list.empty()) return 0.0;
214	
215	        std::array<double, NUM_FLAVORS + 1> sum_r; sum_r.fill(0.0);
216	        std::array<double, NUM_FLAVORS + 1> sum_c; sum_c.fill(0.0);
217	        std::array<int, NUM_FLAVORS + 1> counts; counts.fill(0);
218	
219	        for (const auto& candy : candies_list) {
220	            counts[candy.flavor]++;
221	            sum_r[candy.flavor] += candy.r;
222	            sum_c[candy.flavor] += candy.c;
223	        }
224	
225	        std::array<std::pair<double, double>, NUM_FLAVORS + 1> com_coords;
226	        for (int fl = 1; fl <= NUM_FLAVORS; ++fl) {
227	            if (counts[fl] > 0) {
228	                com_coords[fl] = {sum_r[fl] / counts[fl], sum_c[fl] / counts[fl]};
229	            }
230	        }
231	
232	        double total_manhattan_dist_penalty = 0;
233	        for (const auto& candy : candies_list) {
234	            if (counts[candy.flavor] > 1) { 
235	                const auto& com = com_coords[candy.flavor];
236	                total_manhattan_dist_penalty += std::abs(static_cast<double>(candy.r) - com.first) + 
237	                                                std::abs(static_cast<double>(candy.c) - com.second);
238	            }
239	        }
240	        return total_manhattan_dist_penalty;
241	    }
242	
243	    double calculate_region_penalty() const {
244	        if (candies_list.empty()) return 0.0;
245	        double penalty = 0.0;
246	        for (const auto& candy : candies_list) {
247	            if (!G_flavor_active[candy.flavor]) continue;
248	
249	            const auto& range = G_target_col_ranges[candy.flavor];
250	            int min_target_c = range.first;
251	            int max_target_c = range.second;
252	            
253	            if (min_target_c > max_target_c) continue; 
254	
255	            if (candy.c < min_target_c) {
256	                penalty += (min_target_c - candy.c);
257	            } else if (candy.c > max_target_c) {
258	                penalty += (candy.c - max_target_c);
259	            }
260	        }
261	        return penalty;
262	    }
263	    
264	    double calculate_edge_bonus() const {
265	        double bonus_val = 0.0;
266	        const double PER_CANDY_BONUS_FACTOR = 0.5; 
267	
268	        for (const auto& candy : candies_list) {
269	            if (!G_flavor_active[candy.flavor]) continue;
270	
271	            const auto& range = G_target_col_ranges[candy.flavor];
272	            int min_target_c = range.first;
273	            int max_target_c = range.second;
274	            
275	            if (min_target_c > max_target_c) continue; 
276	
277	            bool in_correct_strip = (candy.c >= min_target_c && candy.c <= max_target_c);
278	            
279	            if (in_correct_strip) {
280	                if (candy.r == 0 || candy.r == GRID_SIZE - 1) { 
281	                    bonus_val += PER_CANDY_BONUS_FACTOR;
282	                }
283	                if ((candy.c == 0 && min_target_c == 0) || 
284	                    (candy.c == GRID_SIZE - 1 && max_target_c == GRID_SIZE - 1)) {
285	                     bonus_val += PER_CANDY_BONUS_FACTOR;
286	                }
287	            }
288	        }
289	        return bonus_val;
290	    }
291	        
292	    double evaluate() const { 
293	        if (candies_list.empty() && turn_num_1_indexed == 0) return 0.0;
294	
295	        long long sum_sq_comp = calculate_sum_sq_comp_size();
296	        double dist_penalty_com = calculate_distance_penalty_CoM();
297	        double region_penalty_val = calculate_region_penalty();
298	        double edge_bonus_val = calculate_edge_bonus();
299	        
300	        double current_turn_double = static_cast<double>(turn_num_1_indexed);
301	        
302	        // Coefficients from Iteration 2 (best scoring), with small tweak to C
303	        double A_coeff_conn = 15.0 + 1.1 * current_turn_double; 
304	        double B_coeff_com_base = std::max(0.0, 170.0 - 1.7 * current_turn_double); 
305	        // Final iteration tweak for C_coeff_region_penalty_direct:
306	        double C_coeff_region_penalty_direct = std::max(2.0, 27.0 - 0.17 * current_turn_double); 
307	        double D_coeff_edge_bonus = 5.0 + 0.2 * current_turn_double; 
308	                
309	        return A_coeff_conn * sum_sq_comp 
310	             - B_coeff_com_base * dist_penalty_com 
311	             - C_coeff_region_penalty_direct * region_penalty_val
312	             + D_coeff_edge_bonus * edge_bonus_val;
313	    }
314	};
