# EVOLVE-BLOCK-START
#include <iostream>
#include <vector>
#include <array>
#include <algorithm>
#include <chrono>
#include <cstring>

const int N = 10;
const int NUM_TURNS = 100;
const int NUM_FLAVORS = 3;
const char DIR_CHARS[] = {'F', 'B', 'L', 'R'};

struct XorshiftRNG {
    uint64_t x;
    XorshiftRNG(uint64_t seed = 0) : x(seed ? seed : 12345678901234ULL) {}
    uint64_t next() {
        x ^= x << 13;
        x ^= x >> 7;
        x ^= x << 17;
        return x;
    }
    int uniform(int lo, int hi) {
        return lo + (int)(next() % (uint64_t)(hi - lo + 1));
    }
};

struct Board {
    uint8_t grid[N][N];
    int num_candies;

    void clear() {
        memset(grid, 0, sizeof(grid));
        num_candies = 0;
    }

    void place(int r, int c, int flavor) {
        grid[r][c] = flavor;
        num_candies++;
    }

    std::pair<int,int> find_pth_empty(int p) const {
        int count = 0;
        for (int r = 0; r < N; r++) {
            for (int c = 0; c < N; c++) {
                if (grid[r][c] == 0) {
                    count++;
                    if (count == p) return {r, c};
                }
            }
        }
        return {-1, -1};
    }

    int count_empty() const {
        return N * N - num_candies;
    }

    void tilt(int dir) {
        if (dir == 0) { // F (up)
            for (int c = 0; c < N; c++) {
                int wr = 0;
                for (int r = 0; r < N; r++) {
                    if (grid[r][c]) {
                        if (r != wr) {
                            grid[wr][c] = grid[r][c];
                            grid[r][c] = 0;
                        }
                        wr++;
                    }
                }
            }
        } else if (dir == 1) { // B (down)
            for (int c = 0; c < N; c++) {
                int wr = N - 1;
                for (int r = N - 1; r >= 0; r--) {
