        num_candies++;
    }

    std::pair<int,int> find_pth_empty(int p) const {
        int count = 0;
        for (int r = 0; r < N; r++) {
            for (int c = 0; c < N; c++) {
                if (grid[r][c] == 0) {
                    count++;
                    if (count == p) return {r, c};
                }
            }
