        if (dir == 0) { // F (up)
            for (int c = 0; c < N; c++) {
                int wr = 0;
                for (int r = 0; r < N; r++) {
                    if (grid[r][c]) {
                        if (r != wr) { grid[wr][c] = grid[r][c]; grid[r][c] = 0; }
                        wr++;
                    }
                }
            }
        } else if (dir == 1) { // B (down)
            for (int c = 0; c < N; c++) {
                int wr = N - 1;
                for (int r = N - 1; r >= 0; r--) {
                    if (grid[r][c]) {
                        if (r != wr) { grid[wr][c] = grid[r][c]; grid[r][c] = 0; }
                        wr--;
                    }
                }
            }
        } else if (dir == 2) { // L
            for (int r = 0; r < N; r++) {
                int wc = 0;
                for (int c = 0; c < N; c++) {
                    if (grid[r][c]) {
                        if (c != wc) { grid[r][wc] = grid[r][c]; grid[r][c] = 0; }
                        wc++;
                    }
                }
            }
        } else { // R
            for (int r = 0; r < N; r++) {
                int wc = N - 1;
                for (int c = N - 1; c >= 0; c--) {
                    if (grid[r][c]) {
                        if (c != wc) { grid[r][wc] = grid[r][c]; grid[r][c] = 0; }
                        wc--;
                    }
                }
            }
        }
    }

    // Count same-flavor adjacencies (each pair counted once)
    int count_adjacency() const {
        int adj = 0;
        for (int r = 0; r < N; r++) {
            for (int c = 0; c < N; c++) {
                if (!grid[r][c]) continue;
                if (r + 1 < N && grid[r+1][c] == grid[r][c]) adj++;
                if (c + 1 < N && grid[r][c+1] == grid[r][c]) adj++;
            }
        }
        return adj;
    }

    // Count different-flavor adjacencies (conflicts)
    int count_conflicts() const {
        int conf = 0;
        for (int r = 0; r < N; r++) {
            for (int c = 0; c < N; c++) {
                if (!grid[r][c]) continue;
                if (r + 1 < N && grid[r+1][c] && grid[r+1][c] != grid[r][c]) conf++;
                if (c + 1 < N && grid[r][c+1] && grid[r][c+1] != grid[r][c]) conf++;
            }
        }
        return conf;
    }

    long long compute_score_numerator() const {
        bool visited[N][N];
        memset(visited, 0, sizeof(visited));
        long long total = 0;
        std::pair<int,int> q[100];
        for (int r = 0; r < N; r++) {
            for (int c = 0; c < N; c++) {
                if (grid[r][c] && !visited[r][c]) {
                    int flavor = grid[r][c];
                    int size = 0;
                    int head = 0, tail = 0;
                    q[tail++] = {r, c};
                    visited[r][c] = true;
                    while (head < tail) {
                        auto [cr, cc] = q[head++];
                        size++;
                        const int dr[] = {-1,1,0,0};
                        const int dc[] = {0,0,-1,1};
                        for (int d = 0; d < 4; d++) {
                            int nr = cr + dr[d], nc = cc + dc[d];
                            if (nr >= 0 && nr < N && nc >= 0 && nc < N &&
                                !visited[nr][nc] && grid[nr][nc] == flavor) {
                                visited[nr][nc] = true;
                                q[tail++] = {nr, nc};
                            }
                        }
                    }
                    total += (long long)size * size;
                }
            }
        }
        return total;
    }

    // Evaluate with emphasis on connectivity + compactness
    // Returns a score suitable for comparing tilt directions
    double evaluate_fast(const int* target_col_center, const int* remaining_of_flavor) const {
