                    int head = 0, tail = 0;
                    q[tail++] = {r, c};
                    visited[r][c] = true;
                    int boundary_empty = 0;
                    while (head < tail) {
                        auto [cr, cc] = q[head++];
                        size++;
                        const int dr[] = {-1,1,0,0};
                        const int dc[] = {0,0,-1,1};
                        for (int d = 0; d < 4; d++) {
                            int nr = cr + dr[d], nc = cc + dc[d];
                            if (nr >= 0 && nr < N && nc >= 0 && nc < N) {
                                if (!visited[nr][nc] && grid[nr][nc] == flavor) {
                                    visited[nr][nc] = true;
                                    q[tail++] = {nr, nc};
                                } else if (grid[nr][nc] == 0) {
