        for (int f = 1; f <= NUM_FLAVORS; f++) {
            score += (double)largest_comp[f] * 2.0;
        }

        // Penalty for distance from target column
        double dist_penalty = 0;
        for (int r = 0; r < N; r++) {
            for (int c = 0; c < N; c++) {
                if (grid[r][c]) {
                    int d = abs(c - target_col_center[grid[r][c]]);
                    dist_penalty += d;
                }
            }
        }
        score -= dist_penalty * 1.5;

