// Global
int flavors[NUM_TURNS];
int flavor_counts[NUM_FLAVORS + 1];
int remaining_flavors[NUM_FLAVORS + 1];
int target_col_center[NUM_FLAVORS + 1]; // target column center for each flavor

void assign_targets() {
    // Sort flavors by count descending
    std::pair<int,int> sorted_fl[3];
    for (int i = 0; i < 3; i++) sorted_fl[i] = {flavor_counts[i+1], i+1};
    std::sort(sorted_fl, sorted_fl + 3, [](auto& a, auto& b){ return a.first > b.first; });

    // Assign target columns proportional to counts
    // Largest gets center-ish, others get sides
    // Actually, assign strips proportionally
    int total = 100;
    int widths[NUM_FLAVORS + 1] = {};
    int col_start[NUM_FLAVORS + 1] = {};

    int used = 0;
    for (int i = 0; i < 3; i++) {
        int fl = sorted_fl[i].second;
        if (i < 2) {
            widths[fl] = (int)round(10.0 * flavor_counts[fl] / total);
            if (widths[fl] < 1) widths[fl] = 1;
        } else {
            widths[fl] = N - used;
        }
        col_start[fl] = used;
        used += widths[fl];
    }
    // Fix if overflow
    if (used > N) {
        widths[sorted_fl[2].second] = N - (used - widths[sorted_fl[2].second]);
    }

    for (int fl = 1; fl <= NUM_FLAVORS; fl++) {
        target_col_center[fl] = col_start[fl] + widths[fl] / 2;
    }
}

// Greedy single-step: pick direction that maximizes fast evaluation
int greedy_pick(const Board& b) {
    double best = -1e18;
    int best_dir = 0;
    for (int d = 0; d < 4; d++) {
        Board tmp = b;
        tmp.tilt(d);
        double score = tmp.evaluate_fast(target_col_center, remaining_flavors);
        if (score > best) {
            best = score;
            best_dir = d;
        }
    }
    return best_dir;
}

// Monte Carlo: do a rollout using greedy policy
long long do_greedy_rollout(Board board, int current_turn, XorshiftRNG& local_rng, int max_steps) {
    int steps = std::min(max_steps, NUM_TURNS - current_turn);
    for (int i = 0; i < steps; i++) {
        int t = current_turn + i;
        int num_empty = board.count_empty();
        if (num_empty == 0) break;
        int p = local_rng.uniform(1, num_empty);
        auto [r, c] = board.find_pth_empty(p);
        board.place(r, c, flavors[t]);

        // Fast greedy: pick direction maximizing adjacency
        int best_adj = -1;
        int best_dir = 0;
        for (int d = 0; d < 4; d++) {
            Board tmp = board;
            tmp.tilt(d);
            int adj = tmp.count_adjacency();
            if (adj > best_adj) {
                best_adj = adj;
                best_dir = d;
            }
        }
        board.tilt(best_dir);
    }
    return board.compute_score_numerator();
}

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);

    for (int i = 0; i < NUM_TURNS; i++) std::cin >> flavors[i];

    memset(flavor_counts, 0, sizeof(flavor_counts));
    for (int i = 0; i < NUM_TURNS; i++) flavor_counts[flavors[i]]++;
    for (int f = 1; f <= NUM_FLAVORS; f++) remaining_flavors[f] = flavor_counts[f];

    assign_targets();

    XorshiftRNG rng(std::chrono::steady_clock::now().time_since_epoch().count());

    Board current_board;
    current_board.clear();

    auto global_start = std::chrono::steady_clock::now();
    const int TIME_LIMIT_MS = 1900;

    for (int t = 0; t < NUM_TURNS; t++) {
        int p;
        std::cin >> p;
        auto [r, c] = current_board.find_pth_empty(p);
        current_board.place(r, c, flavors[t]);
        remaining_flavors[flavors[t]]--;

        if (t == NUM_TURNS - 1) {
            // Last turn: just pick best immediate
            int best_dir = greedy_pick(current_board);
            std::cout << DIR_CHARS[best_dir] << std::endl;
            current_board.tilt(best_dir);
            continue;
        }

        auto turn_start = std::chrono::steady_clock::now();
        int elapsed_total_ms = (int)std::chrono::duration_cast<std::chrono::milliseconds>(
            turn_start - global_start).count();
        int remaining_ms = TIME_LIMIT_MS - elapsed_total_ms;
        int turns_left = NUM_TURNS - t;

        // Allocate more time to early turns (diminishing returns later)
        // Weight: proportional to remaining turns
        int budget_ms = std::max(1, (int)(remaining_ms * 2.0 / (turns_left + 1)));
        budget_ms = std::min(budget_ms, remaining_ms - turns_left + 1);
        if (budget_ms < 1) budget_ms = 1;

        // Monte Carlo with greedy rollouts
        // Limit rollout depth based on remaining turns and time
        int rollout_depth = std::min(NUM_TURNS - t - 1, 30); // max 30 steps ahead

        long long dir_scores[4] = {};
        int dir_counts[4] = {};

        auto deadline = turn_start + std::chrono::milliseconds(budget_ms);

        int batch = 0;
        while (true) {
            auto now = std::chrono::steady_clock::now();
            if (now >= deadline) break;

            for (int d = 0; d < 4; d++) {
                Board after_tilt = current_board;
                after_tilt.tilt(d);
                long long score = do_greedy_rollout(after_tilt, t + 1, rng, rollout_depth);
                dir_scores[d] += score;
                dir_counts[d]++;
            }
            batch++;

            if (batch % 2 == 0) {
                auto now2 = std::chrono::steady_clock::now();
                if (now2 >= deadline) break;
            }
        }

        // If we couldn't do any rollouts (time pressure), fall back to greedy
        int best_dir;
        if (batch == 0) {
            best_dir = greedy_pick(current_board);
        } else {
            best_dir = 0;
            double best_avg = -1e18;
            for (int d = 0; d < 4; d++) {
                if (dir_counts[d] > 0) {
                    double avg = (double)dir_scores[d] / dir_counts[d];
                    if (avg > best_avg) {
                        best_avg = avg;
                        best_dir = d;
                    }
                }
            }
        }

        std::cout << DIR_CHARS[best_dir] << std::endl;
        current_board.tilt(best_dir);
    }

    return 0;
}
