    for (int i = 0; i < 3; i++) {
        int fl = sorted_fl[i].second;
        int w;
        if (i < 2) {
            w = std::max(1, (int)round(10.0 * flavor_counts[fl] / 100.0));
        } else {
            w = N - used;
        }
        if (used + w > N) w = N - used;
        target_col_lo[fl] = used;
        target_col_hi[fl] = used + w - 1;
        target_col_center[fl] = used + w / 2;
        used += w;
    }
}

// Evaluation function combining:
// 1. Connected component score (sum of n_i^2) - the actual objective
// 2. Spatial penalty: distance of each candy from its target column strip
// 3. Growth potential: empty neighbors adjacent to flavor-matched component
// 4. Compactness: variance of positions within each flavor
double evaluate(const Board& b, int turn) {
    bool visited[N][N];
    memset(visited, 0, sizeof(visited));
    std::pair<int,int> q[100];

    long long sum_sq = 0;
    int largest_comp[NUM_FLAVORS + 1] = {};
    int total_boundary_empty[NUM_FLAVORS + 1] = {};

    for (int r = 0; r < N; r++)
        for (int c = 0; c < N; c++)
            if (b.grid[r][c] && !visited[r][c]) {
                int fl = b.grid[r][c], size = 0;
                int head = 0, tail = 0;
                int boundary = 0;
                q[tail++] = {r, c};
                visited[r][c] = true;
                while (head < tail) {
                    auto [cr, cc] = q[head++]; size++;
                    for (int d = 0; d < 4; d++) {
                        int nr = cr + DR[d], nc = cc + DC[d];
                        if (nr >= 0 && nr < N && nc >= 0 && nc < N) {
                            if (!visited[nr][nc] && b.grid[nr][nc] == fl) {
                                visited[nr][nc] = true;
                                q[tail++] = {nr, nc};
                            } else if (b.grid[nr][nc] == 0) {
                                boundary++;
                            }
                        }
                    }
                }
                sum_sq += (long long)size * size;
                if (size > largest_comp[fl]) largest_comp[fl] = size;
                total_boundary_empty[fl] += boundary;
            }

    double score = (double)sum_sq;

    // Spatial separation penalty (push flavors toward their assigned strip)
    double dist_penalty = 0;
    for (int r = 0; r < N; r++)
        for (int c = 0; c < N; c++)
            if (b.grid[r][c]) {
                int fl = b.grid[r][c];
                if (c < target_col_lo[fl]) dist_penalty += target_col_lo[fl] - c;
                else if (c > target_col_hi[fl]) dist_penalty += c - target_col_hi[fl];
            }

    // Center-of-mass compactness per flavor
    double com_penalty = 0;
    double sum_r[NUM_FLAVORS + 1] = {}, sum_c[NUM_FLAVORS + 1] = {};
    int cnt[NUM_FLAVORS + 1] = {};
    for (int r = 0; r < N; r++)
        for (int c = 0; c < N; c++)
            if (b.grid[r][c]) {
                int fl = b.grid[r][c];
                sum_r[fl] += r; sum_c[fl] += c; cnt[fl]++;
            }
    for (int fl = 1; fl <= NUM_FLAVORS; fl++) {
        if (cnt[fl] <= 1) continue;
        double mr = sum_r[fl] / cnt[fl], mc = sum_c[fl] / cnt[fl];
        for (int r = 0; r < N; r++)
            for (int c = 0; c < N; c++)
                if (b.grid[r][c] == fl)
                    com_penalty += std::abs(r - mr) + std::abs(c - mc);
    }

    // Growth potential bonus
    double growth_bonus = 0;
    for (int fl = 1; fl <= NUM_FLAVORS; fl++) {
        growth_bonus += (double)total_boundary_empty[fl] * remaining_flavors[fl] * 0.01;
    }

    // Dominant component bonus
    double dom_bonus = 0;
    for (int fl = 1; fl <= NUM_FLAVORS; fl++) {
        dom_bonus += (double)largest_comp[fl] * largest_comp[fl] * 0.5;
    }

    // Adaptive weights based on turn
    double t_frac = (double)turn / NUM_TURNS;
    double w_conn = 10.0 + 5.0 * t_frac;       // connectivity matters more later
    double w_dist = std::max(0.0, 25.0 - 20.0 * t_frac); // strip penalty matters early
    double w_com = std::max(0.0, 3.0 - 2.5 * t_frac);   // compactness matters early
    double w_growth = std::max(0.0, 5.0 - 5.0 * t_frac); // growth only matters early
    double w_dom = 3.0 + 2.0 * t_frac;         // dominant component bonus

    return w_conn * score - w_dist * dist_penalty - w_com * com_penalty
           + w_growth * growth_bonus + w_dom * dom_bonus;
}

// Expectimax with configurable depth and samples
// depth 3 with aggressive pruning for speed
struct ExpectimaxConfig {
    int samples[3]; // samples at each depth level
};

double expectimax(const Board& state, int turn_just_placed, int depth, const ExpectimaxConfig& cfg);

double expectimax(const Board& state, int turn_just_placed, int depth, const ExpectimaxConfig& cfg) {
    if (depth == 0 || turn_just_placed >= NUM_TURNS) {
        return evaluate(state, turn_just_placed);
    }

    int num_empty = state.count_empty();
    if (num_empty == 0) return evaluate(state, turn_just_placed);

    int next_flavor = flavors[turn_just_placed]; // 0-indexed
    int level = cfg.samples[0] > 0 ? 0 : 1; // unused, use depth-based indexing
    int sample_idx = (cfg.samples[0] > cfg.samples[1]) ?
                     (3 - depth) : 0; // depth indexing
    // Actually: depth goes 3->2->1, so index = 3-depth = 0,1,2
    int idx = 3 - depth;
    if (idx < 0) idx = 0;
    if (idx > 2) idx = 2;
    int num_samples = std::min(cfg.samples[idx], num_empty);
    if (num_samples <= 0) return evaluate(state, turn_just_placed);

    double total = 0.0;
    for (int s = 0; s < num_samples; s++) {
        int p;
        if (num_samples >= num_empty) {
            p = s + 1;
        } else {
            p = global_rng.uniform(1, num_empty);
        }

        Board placed = state;
        auto [r, c] = placed.find_pth_empty(p);
        placed.place(r, c, next_flavor);

        // Find best direction
        double best_val = -1e18;
        for (int d = 0; d < 4; d++) {
            Board tilted = placed;
            tilted.tilt(d);
            double val = expectimax(tilted, turn_just_placed + 1, depth - 1, cfg);
            if (val > best_val) best_val = val;
        }
        total += best_val;
    }
    return total / num_samples;
}

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);

    for (int i = 0; i < NUM_TURNS; i++) std::cin >> flavors[i];

    memset(flavor_counts, 0, sizeof(flavor_counts));
    for (int i = 0; i < NUM_TURNS; i++) flavor_counts[flavors[i]]++;
    for (int f = 1; f <= NUM_FLAVORS; f++) remaining_flavors[f] = flavor_counts[f];

    assign_targets();

