    current_board.clear();

    auto global_start = std::chrono::steady_clock::now();
    const int TIME_LIMIT_MS = 1900;

    for (int t = 0; t < NUM_TURNS; t++) {
        int p;
        std::cin >> p;
        auto [r, c] = current_board.find_pth_empty(p);
        current_board.place(r, c, flavors[t]);
        remaining_flavors[flavors[t]]--;

        auto turn_start = std::chrono::steady_clock::now();
        int elapsed_ms = (int)std::chrono::duration_cast<std::chrono::milliseconds>(
            turn_start - global_start).count();
        int remaining_ms = TIME_LIMIT_MS - elapsed_ms;
        int turns_left = NUM_TURNS - t;

        // Adaptive depth/samples based on time budget
        ExpectimaxConfig cfg;
        if (remaining_ms > 1500 && t < 50) {
            // Early game, lots of time: depth 3 with moderate samples
            cfg.samples[0] = 15; cfg.samples[1] = 7; cfg.samples[2] = 3;
        } else if (remaining_ms > 800) {
            // Mid game: depth 3 with fewer samples
            cfg.samples[0] = 12; cfg.samples[1] = 5; cfg.samples[2] = 0;
        } else if (remaining_ms > 300) {
            // Late game: depth 2
            cfg.samples[0] = 10; cfg.samples[1] = 0; cfg.samples[2] = 0;
        } else {
            // Very late: depth 1 (just greedy)
            cfg.samples[0] = 0; cfg.samples[1] = 0; cfg.samples[2] = 0;
        }

        // Determine effective depth
        int eff_depth = 0;
        if (cfg.samples[0] > 0) eff_depth = 1;
        if (cfg.samples[1] > 0) eff_depth = 2;
        if (cfg.samples[2] > 0) eff_depth = 3;

        if (t == NUM_TURNS - 1) eff_depth = 0; // Last turn: just evaluate

        int best_dir = 0;
        double best_val = -1e18;

        for (int d = 0; d < 4; d++) {
            Board tilted = current_board;
            tilted.tilt(d);

            double val;
            if (eff_depth == 0) {
                val = evaluate(tilted, t + 1);
            } else {
                val = expectimax(tilted, t + 1, eff_depth, cfg);
            }
            if (val > best_val) {
                best_val = val;
                best_dir = d;
            }
        }

        std::cout << DIR_CHARS[best_dir] << std::endl;
        current_board.tilt(best_dir);
    }

    return 0;
}
