#include <iostream>
#include <array>
#include <algorithm>
#include <chrono>
#include <cstring>
#include <cmath>

const int N = 10;
const int NUM_TURNS = 100;
const int NUM_FLAVORS = 3;
const char DIR_CHARS[] = {'F', 'B', 'L', 'R'};
const int DR[] = {-1, 1, 0, 0};
const int DC[] = {0, 0, -1, 1};

struct XorshiftRNG {
    uint64_t x;
    XorshiftRNG(uint64_t seed = 0) : x(seed ? seed : 98765432101234ULL) {}
    uint64_t next() {
        x ^= x << 13;
        x ^= x >> 7;
        x ^= x << 17;
        return x;
    }
    int uniform(int lo, int hi) {
        return lo + (int)(next() % (uint64_t)(hi - lo + 1));
    }
};

XorshiftRNG global_rng;

struct Board {
    uint8_t grid[N][N];
    int num_candies;

    void clear() {
        memset(grid, 0, sizeof(grid));
        num_candies = 0;
    }

    void place(int r, int c, int flavor) {
        grid[r][c] = flavor;
        num_candies++;
    }

    std::pair<int,int> find_pth_empty(int p) const {
        int count = 0;
        for (int r = 0; r < N; r++)
            for (int c = 0; c < N; c++)
                if (grid[r][c] == 0)
                    if (++count == p) return {r, c};
        return {-1, -1};
    }

    int count_empty() const { return N * N - num_candies; }

    void tilt(int dir) {
        if (dir == 0) {
            for (int c = 0; c < N; c++) {
                int wr = 0;
                for (int r = 0; r < N; r++)
                    if (grid[r][c]) {
                        if (r != wr) { grid[wr][c] = grid[r][c]; grid[r][c] = 0; }
                        wr++;
                    }
            }
        } else if (dir == 1) {
            for (int c = 0; c < N; c++) {
                int wr = N - 1;
                for (int r = N - 1; r >= 0; r--)
                    if (grid[r][c]) {
                        if (r != wr) { grid[wr][c] = grid[r][c]; grid[r][c] = 0; }
                        wr--;
                    }
            }
        } else if (dir == 2) {
            for (int r = 0; r < N; r++) {
                int wc = 0;
                for (int c = 0; c < N; c++)
                    if (grid[r][c]) {
                        if (c != wc) { grid[r][wc] = grid[r][c]; grid[r][c] = 0; }
                        wc++;
                    }
            }
        } else {
            for (int r = 0; r < N; r++) {
                int wc = N - 1;
                for (int c = N - 1; c >= 0; c--)
                    if (grid[r][c]) {
                        if (c != wc) { grid[r][wc] = grid[r][c]; grid[r][c] = 0; }
                        wc--;
                    }
            }
        }
    }
};

// Global data
int flavors[NUM_TURNS];
int flavor_counts[NUM_FLAVORS + 1];

// Target column ranges
int target_col_lo[NUM_FLAVORS + 1];
int target_col_hi[NUM_FLAVORS + 1];
bool flavor_active[NUM_FLAVORS + 1];

void assign_targets() {
    std::pair<int,int> sorted_fl[3];
    for (int i = 0; i < 3; i++) sorted_fl[i] = {flavor_counts[i+1], i+1};
    std::sort(sorted_fl, sorted_fl + 3, [](auto& a, auto& b){ return a.first > b.first; });

    double total = 0;
    for (int i = 0; i < 3; i++) total += sorted_fl[i].first;
    if (total == 0) total = 1;

    int widths[NUM_FLAVORS + 1] = {};
    int sum_w = 0;
    for (int i = 0; i < 3; i++) {
        int fl = sorted_fl[i].second;
        widths[fl] = (int)std::floor(N * sorted_fl[i].first / total);
        if (widths[fl] < 1 && sorted_fl[i].first > 0) widths[fl] = 1;
        sum_w += widths[fl];
    }
    int remaining = N - sum_w;
    for (int i = 0; i < remaining; i++) {
        widths[sorted_fl[i % 3].second]++;
    }

    int used = 0;
    for (int i = 0; i < 3; i++) {
        int fl = sorted_fl[i].second;
        target_col_lo[fl] = used;
        target_col_hi[fl] = used + widths[fl] - 1;
        used += widths[fl];
    }

    for (int fl = 1; fl <= NUM_FLAVORS; fl++) {
        flavor_active[fl] = (flavor_counts[fl] > 0);
    }
}

// Fast evaluation: connectivity + CoM + region + edge + dominant component
// Optimized to avoid unnecessary work
double evaluate(const Board& b, int turn) {
    bool visited[N][N];
    memset(visited, 0, sizeof(visited));
    std::pair<int,int> q[100];

    long long sum_sq = 0;
    int largest_comp[NUM_FLAVORS + 1] = {};

    for (int r = 0; r < N; r++)
        for (int c = 0; c < N; c++)
            if (b.grid[r][c] && !visited[r][c]) {
                int fl = b.grid[r][c], size = 0;
                int head = 0, tail = 0;
                q[tail++] = {r, c};
                visited[r][c] = true;
                while (head < tail) {
                    auto [cr, cc] = q[head++]; size++;
                    for (int d = 0; d < 4; d++) {
                        int nr = cr + DR[d], nc = cc + DC[d];
                        if (nr >= 0 && nr < N && nc >= 0 && nc < N &&
                            !visited[nr][nc] && b.grid[nr][nc] == fl) {
                            visited[nr][nc] = true;
                            q[tail++] = {nr, nc};
                        }
                    }
                }
                sum_sq += (long long)size * size;
                if (size > largest_comp[fl]) largest_comp[fl] = size;
            }

    // CoM penalty + region penalty in one pass
    double sum_r[NUM_FLAVORS + 1] = {}, sum_c[NUM_FLAVORS + 1] = {};
    int cnt[NUM_FLAVORS + 1] = {};
    double region_penalty = 0;
    double edge_bonus = 0;

    for (int r = 0; r < N; r++)
        for (int c = 0; c < N; c++)
            if (b.grid[r][c]) {
                int fl = b.grid[r][c];
                sum_r[fl] += r; sum_c[fl] += c; cnt[fl]++;

                // Region penalty
                if (c < target_col_lo[fl]) region_penalty += target_col_lo[fl] - c;
                else if (c > target_col_hi[fl]) region_penalty += c - target_col_hi[fl];

                // Edge bonus (in correct strip)
                if (c >= target_col_lo[fl] && c <= target_col_hi[fl]) {
                    if (r == 0 || r == N - 1) edge_bonus += 0.5;
                    if ((c == 0 && target_col_lo[fl] == 0) ||
                        (c == N - 1 && target_col_hi[fl] == N - 1))
                        edge_bonus += 0.5;
                }
            }

    // CoM penalty
    double com_penalty = 0;
    for (int fl = 1; fl <= NUM_FLAVORS; fl++) {
        if (cnt[fl] <= 1) continue;
        double mr = sum_r[fl] / cnt[fl], mc = sum_c[fl] / cnt[fl];
        for (int r = 0; r < N; r++)
            for (int c = 0; c < N; c++)
                if (b.grid[r][c] == fl)
                    com_penalty += std::abs(r - mr) + std::abs(c - mc);
    }

    // Dominant component bonus: reward concentration into single component
    double dom_bonus = 0;
    for (int fl = 1; fl <= NUM_FLAVORS; fl++) {
        if (cnt[fl] > 0) {
            dom_bonus += (double)largest_comp[fl] * largest_comp[fl] * 0.3;
        }
    }

    double t = (double)turn;

    // Proven coefficients from baseline + dominant component bonus
    double A = 15.0 + 1.1 * t;
    double B = std::max(0.0, 170.0 - 1.7 * t);
    double C = std::max(2.0, 27.0 - 0.17 * t);
    double D = 5.0 + 0.2 * t;

    return A * sum_sq - B * com_penalty - C * region_penalty + D * edge_bonus + dom_bonus;
}

// Expectimax depth 2 with fixed sample counts
const int SAMPLES_D2 = 23;
const int SAMPLES_D1 = 9;

double expectimax_d1(const Board& state, int next_turn) {
    if (next_turn >= NUM_TURNS) return evaluate(state, next_turn);
    int num_empty = state.count_empty();
    if (num_empty == 0) return evaluate(state, next_turn);

    int next_flavor = flavors[next_turn];
    int ns = std::min(SAMPLES_D1, num_empty);

    double total = 0.0;
    for (int s = 0; s < ns; s++) {
        int p = (ns >= num_empty) ? s + 1 : global_rng.uniform(1, num_empty);
        Board placed = state;
        auto [r, c] = placed.find_pth_empty(p);
        placed.place(r, c, next_flavor);

        double best_val = -1e18;
        for (int d = 0; d < 4; d++) {
            Board tilted = placed;
            tilted.tilt(d);
            double val = evaluate(tilted, next_turn + 1);
            if (val > best_val) best_val = val;
        }
        total += best_val;
    }
    return total / ns;
}

double expectimax_d2(const Board& state, int next_turn) {
    if (next_turn >= NUM_TURNS) return evaluate(state, next_turn);
    int num_empty = state.count_empty();
    if (num_empty == 0) return evaluate(state, next_turn);

    int next_flavor = flavors[next_turn];
    int ns = std::min(SAMPLES_D2, num_empty);

    double total = 0.0;
    for (int s = 0; s < ns; s++) {
        int p = (ns >= num_empty) ? s + 1 : global_rng.uniform(1, num_empty);
        Board placed = state;
        auto [r, c] = placed.find_pth_empty(p);
        placed.place(r, c, next_flavor);

        double best_val = -1e18;
        for (int d = 0; d < 4; d++) {
            Board tilted = placed;
            tilted.tilt(d);
            double val = expectimax_d1(tilted, next_turn + 1);
            if (val > best_val) best_val = val;
        }
        total += best_val;
    }
    return total / ns;
}

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);

    for (int i = 0; i < NUM_TURNS; i++) std::cin >> flavors[i];

    memset(flavor_counts, 0, sizeof(flavor_counts));
    for (int i = 0; i < NUM_TURNS; i++) flavor_counts[flavors[i]]++;

    assign_targets();

    global_rng = XorshiftRNG(std::chrono::steady_clock::now().time_since_epoch().count());

    Board current_board;
    current_board.clear();

    for (int t = 0; t < NUM_TURNS; t++) {
        int p;
        std::cin >> p;
        auto [r, c] = current_board.find_pth_empty(p);
        current_board.place(r, c, flavors[t]);

        int best_dir = 0;
        double best_val = -1e18;

        for (int d = 0; d < 4; d++) {
            Board tilted = current_board;
            tilted.tilt(d);
            double val = expectimax_d2(tilted, t + 1);
            if (val > best_val) {
                best_val = val;
                best_dir = d;
            }
        }

        std::cout << DIR_CHARS[best_dir] << std::endl;
        current_board.tilt(best_dir);
    }

    return 0;
}
# EVOLVE-BLOCK-END

