// CoM penalty using sum of absolute deviations from mean
// |x_i - mean| summed = can be computed as:
// sum |x_i - mean| = sum_above(x_i - mean) + sum_below(mean - x_i)
// But it's equivalent to: sum|x_i - mean| for pre-computed positions
// We need per-flavor position lists. Use arrays since grid is small.
double com_penalty = 0;
for (int fl = 1; fl <= NUM_FLAVORS; fl++) {
    if (cnt[fl] <= 1) continue;
    double mr = sum_r[fl] / cnt[fl], mc = sum_c[fl] / cnt[fl];
    // sum |r_i - mr| = sum_r[fl] - cnt[fl]*mr for items above, etc.
    // Actually we need exact sum. Use precomputed sums of squares approach:
    // sum|x-m| can't be simplified easily. But we can compute:
    // sum(|r-mr|) + sum(|c-mc|) from the second moments
    // Var = E[x^2] - E[x]^2, but |x-m| != sqrt(var)
    // Just use the L1 formula with sorted positions... too complex.
    // Instead, compute sum|x_i - floor(mean)| which is close enough
    // Actually the fastest approach: for each candy we already visited above.
    // The issue is we iterate grid twice. Let's just accept the O(100) cost
    // but make it branchless
    double penalty_fl = 0;
    for (int r = 0; r < N; r++)
        for (int c = 0; c < N; c++)
            if (b.grid[r][c] == fl) {
                double dr = r - mr; if (dr < 0) dr = -dr;
                double dc = c - mc; if (dc < 0) dc = -dc;
                penalty_fl += dr + dc;
            }
    com_penalty += penalty_fl;
}

